CREATE VIEW `ads_monitor_collect_time_lag_view` (`dt` COMMENT "日期", `data_tp` COMMENT "类型，1业务数据，2日志数据", `biz_class` COMMENT "上报源", `receive_heartbeat_diff` COMMENT "时间差", `heartbeat_time` COMMENT "心跳时间", `receive_time` COMMENT "接收时间", `sr_createtime`, `sr_updatetime`) AS SELECT `dwd`.`dwd_data_quality_link_monitor`.`dt`, `dwd`.`dwd_data_quality_link_monitor`.`date_tp`, `dwd`.`dwd_data_quality_link_monitor`.`biz_class`, (unix_timestamp(`dwd`.`dwd_data_quality_link_monitor`.`receive_time`)) - (unix_timestamp(`dwd`.`dwd_data_quality_link_monitor`.`heartbeat_time`)) AS `time_diff`, `dwd`.`dwd_data_quality_link_monitor`.`heartbeat_time`, `dwd`.`dwd_data_quality_link_monitor`.`receive_time`, `dwd`.`dwd_data_quality_link_monitor`.`sr_createtime`, `dwd`.`dwd_data_quality_link_monitor`.`sr_updatetime`
FROM `dwd`.`dwd_data_quality_link_monitor`
WHERE `dwd`.`dwd_data_quality_link_monitor`.`kafka_tp` IN (1, 3);